def connect_wifi(ssid, password, timeout_s=15):
    if network is None:
        return None
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        wlan.connect(ssid, password)
        t0 = time.time()
        while not wlan.isconnected() and (time.time() - t0) < timeout_s:
            time.sleep(0.2)
    return wlan


